// Warm-up ramp + daily cap + pick the next un-contacted lead.
const staticData = $getWorkflowStaticData('global');
const now = new Date();
if (!staticData.startDate) { staticData.startDate = now.toISOString(); }
const start = new Date(staticData.startDate);
const dayNum = Math.floor((now - start) / (1000 * 60 * 60 * 24)) + 1;

let cap;
if (dayNum <= 7) cap = 5;
else if (dayNum <= 14) cap = 8;
else if (dayNum <= 21) cap = 12;
else cap = 15;

const todayStr = now.toISOString().slice(0, 10);
const rows = items.map(i => i.json);
const sentToday = rows.filter(r => String(r.sent_at || '').slice(0, 10) === todayStr).length;
if (sentToday >= cap) {
  return [{ json: { proceed: false, reason: 'Daily cap reached', cap, sentToday, dayNum } }];
}

const next = rows.find(r => {
  const status = String(r.status || '').trim().toLowerCase();
  const email = String(r['Email'] || '').trim();
  return email.includes('@') && (status === '' || status === 'pending');
});
if (!next) {
  return [{ json: { proceed: false, reason: 'No pending leads left', cap, sentToday, dayNum } }];
}
return [{ json: { proceed: true, cap, sentToday, dayNum, lead: next, row_number: next.row_number } }];

const lead = $json.lead || {};

const system = `You are Shafeel writing a SHORT, casual, confident cold email to one prospect. You build AI agent systems and outbound automation for companies and agencies, done-for-you on commission.

STYLE RULES:
- 3 to 4 short sentences total. Never more.
- Plain text only. Sound like one founder writing to another: confident, direct, human, not salesy.
- Open with "Hey [first name]," then ONE genuine, specific sentence about their company based on the company description provided. Make it real and personal, never generic flattery.
- NEVER use em-dashes or double hyphens. Use commas, periods, or new sentences instead.
- No buzzwords, no exclamation marks, no marketing-speak, no ALL CAPS, no links, no images.
- Use ONLY the true facts below. Never invent results, numbers, clients, or claims.
- Close with the call to action, then sign off on its own line with just: Shafeel

TRUE FACTS (do not go beyond these):
- I recently added $20K for a SaaS client in Indiana by building them an outbound system.
- I build AI agent systems and outbound automation for clients, working on commission.
- Guarantee I can make: I will get you your next 5 clients or I will work for free until I do.

CALL TO ACTION (phrase it naturally, do not paste any link):
- Offer a quick 15 minute call later today or tomorrow afternoon, and say you will send a Google Meet link.

Output STRICT JSON only, no markdown, exactly:
{"subject": "...", "body": "..."}
The subject must be casual, lowercase-ish, under 5 words, and must not look like an ad.`;

const userMsg = `Write the cold email now for this lead.
First name: ${lead['First Name'] || 'there'}
Company: ${lead['Company Name'] || ''}
Title: ${lead['Title'] || ''}
Industry: ${lead['Industry'] || ''}
Company description (use this for the personalized opening line): ${lead['Company Short Description'] || lead['Headline'] || 'no description available'}

If no company description is available, open with a genuine line based on their title or industry instead. Keep it to 3 or 4 short sentences. No em-dashes. Sign off as Shafeel.`;

const body = { model: 'claude-sonnet-4-6', max_tokens: 500, system, messages: [{ role: 'user', content: userMsg }] };
return [{ json: { body } }];

const resp = $json;
let text = '';
try { text = resp.content && resp.content[0] && resp.content[0].text ? resp.content[0].text : ''; } catch (e) { text = ''; }
text = text.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();
let parsed;
try { parsed = JSON.parse(text); } catch (e) { parsed = { subject: 'quick question', body: text || 'Hi, reaching out.' }; }

const decide = $('Pick next lead').item.json;
const lead = decide.lead || {};
return [{ json: {
  to: lead['Email'],
  first_name: lead['First Name'] || '',
  company: lead['Company Name'] || '',
  row_number: decide.row_number,
  subject: String(parsed.subject || 'quick question').slice(0, 120),
  body: String(parsed.body || '').trim()
} }];

// Pick the next ACTIVE lead whose follow-up is due.
// Shares the same daily ramp cap as the initial sender (counts sent_at == today).
const sd = $getWorkflowStaticData('global');
const now = new Date();
if (!sd.startDate) sd.startDate = now.toISOString();
const dayNum = Math.floor((now - new Date(sd.startDate)) / 864e5) + 1;

let cap;
if (dayNum <= 7) cap = 5;
else if (dayNum <= 14) cap = 8;
else if (dayNum <= 21) cap = 12;
else cap = 15;

const today = now.toISOString().slice(0, 10);
const rows = items.map(i => i.json);
const sentToday = rows.filter(r => String(r.sent_at || '').slice(0, 10) === today).length;
if (sentToday >= cap) {
  return [{ json: { proceed: false, reason: 'Daily cap reached', cap, sentToday } }];
}

// Days to wait: 3 days before email 2 (stage 1), 4 more before email 3 (stage 2).
const DELAY = { 1: 3, 2: 4 };
const daysSince = ts => {
  if (!ts) return 999;
  const d = new Date(String(ts).slice(0, 10));
  return (now - d) / 864e5;
};

const next = rows.find(r => {
  const status = String(r.status || '').trim().toLowerCase();
  const stage = Number(r.stage || 0);
  const email = String(r['Email'] || '').trim();
  return email.includes('@') && status === 'active' && (stage === 1 || stage === 2) && daysSince(r.sent_at) >= DELAY[stage];
});
if (!next) {
  return [{ json: { proceed: false, reason: 'No follow-ups due', cap, sentToday } }];
}

return [{ json: {
  proceed: true, cap, sentToday,
  lead: next, row_number: next.row_number,
  stage: Number(next.stage || 0),
  message_id: next.message_id,
  thread_id: next.thread_id,
} }];

// ====== SET YOUR NAME ======
const SENDER_NAME = 'Shafeel';
// ===========================

const lead = $json.lead || {};
const stage = Number($json.stage);   // 1 => sending email 2; 2 => sending email 3 (final)
const fuNum = stage;

const system = `You are ${SENDER_NAME} writing a SHORT follow-up to a cold email the prospect did not reply to. This is follow-up number ${fuNum} of 2.

RULES:
- 1 to 3 sentences only. Shorter than the first email.
- Friendly and low pressure. No guilt, no "just bumping this", no pushiness.
- Add ONE new angle, a quick proof point, or a simple yes or no question. Do NOT repeat the whole pitch.
- If this is follow-up number 2, make it a short, polite final check-in and offer to close the loop.
- NEVER use em-dashes or double hyphens. No links, no images. Plain text.
- Sign off on its own line with just: ${SENDER_NAME}

Output STRICT JSON only, no markdown, exactly:
{"subject": "", "body": "..."}
Leave subject as an empty string, the email is sent as a reply in the same thread.`;

const userMsg = `Prospect first name: ${lead['First Name'] || 'there'}
Company: ${lead['Company Name'] || ''}
What they do: ${lead['Company Short Description'] || lead['Headline'] || 'unknown'}`;

const body = { model: 'claude-sonnet-4-6', max_tokens: 300, system, messages: [{ role: 'user', content: userMsg }] };
return [{ json: { body } }];

// Parse the follow-up text and carry the IDs needed to reply + update the row.
const resp = $json;
let text = '';
try { text = resp.content && resp.content[0] && resp.content[0].text ? resp.content[0].text : ''; } catch (e) { text = ''; }
text = text.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();
let p;
try { p = JSON.parse(text); } catch (e) { p = { subject: '', body: text || 'Just following up in case this is useful.' }; }

const d = $('Decide follow-up').item.json;
return [{ json: {
  message_id: d.message_id,
  thread_id: d.thread_id,
  row_number: d.row_number,
  stage: d.stage,
  next_stage: Number(d.stage) + 1,
  body: String(p.body || '').trim(),
} }];

// Collect unique sender email addresses from recent inbox messages.
const emails = items.map(i => {
  const f = i.json.from || i.json.From || '';
  const m = String(f).match(/[\w.+-]+@[\w.-]+\.[A-Za-z]{2,}/);
  return m ? m[0].toLowerCase() : null;
}).filter(Boolean);
return [{ json: { senders: Array.from(new Set(emails)) } }];

// Any ACTIVE lead who shows up as an inbox sender has replied -> mark them 'replied'
// so the follow-up flow stops emailing them.
const senders = $('Get inbox senders').item.json.senders || [];
const set = new Set(senders.map(s => String(s).toLowerCase()));
const rows = items.map(i => i.json);

const out = rows.filter(r => {
  const email = String(r['Email'] || '').trim().toLowerCase();
  const status = String(r.status || '').trim().toLowerCase();
  return email && set.has(email) && status === 'active';
}).map(r => ({ json: { row_number: r.row_number, status: 'replied' } }));

return out;
